def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = 1000 + (ratio - 1) * 150
            continue
        elif ratio == 1:
            priorities[i] = 200
            continue
        surplus = capacity - item
        score = 0
        for j in range(1, 8):
            factor = (surplus ** j) / (capacity ** j)
            if factor < 0.05:
                score += factor * 100
            elif factor < 0.2:
                score += factor * 20 / j
            else:
                score += np.log1p(factor) / (j + 1)
        penalty = 0
        for k in range(n):
            if k != i:
                dist = abs(capacity - bins[k])
                if dist < item:
                    penalty += (item - dist) / (bins[k] + 1)
        if penalty > 0.5:
            priorities[i] = score * 0.5 + penalty * 5
        else:
            if score < 0.1:
                priorities[i] = score * 15
            else:
                priorities[i] = 1 / (score + 1 + penalty)
        if i % 2 == 0:
            priorities[i] *= 1.1
        else:
            priorities[i] *= 0.9
    return priorities
